CREATE DATABASE IF NOT EXISTS echobaduga; USE echobaduga; CREATE TABLE IF NOT EXISTS users (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(255) NOT NULL, email VARCHAR(255) UNIQUE NOT NULL, password VARCHAR(255) NOT NULL, role VARCHAR(50) DEFAULT 'listener', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP); CREATE TABLE IF NOT EXISTS songs (id INT AUTO_INCREMENT PRIMARY KEY, title VARCHAR(255) NOT NULL, artist_name VARCHAR(255) NOT NULL, cover_emoji VARCHAR(50) DEFAULT '🎵', duration VARCHAR(10) DEFAULT '3:30', like_count INT DEFAULT 0, play_count INT DEFAULT 0, genre VARCHAR(50) DEFAULT 'Folk', file_url VARCHAR(255) NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);INSERT INTO songs (title, artist_name, file_url) VALUES ('#Amma#Murugesh Porthy#BadagaNewSongs#BadagaSongs#BadagaNewSongs2020 - PaaS Studio''s', 'Baduga Artist', 'http://localhost/song/song1.mp3');INSERT INTO songs (title, artist_name, file_url) VALUES ('Aaluna Manasu Hethega Baduga New song  Baduga New Hethe Song  Pedhuva Raman  YNB Family - Pedhuva Raman', 'Baduga Artist', 'http://localhost/song/song2.mp3');INSERT INTO songs (title, artist_name, file_url) VALUES ('AALUNA THATTE  BADUGA HETHEY SONG  MURUGESH PORTHY  RANGASAMY DEVARAJ  VISHAK RAJAGOPALAN - Murugesh Porthy', 'Baduga Artist', 'http://localhost/song/song3.mp3');INSERT INTO songs (title, artist_name, file_url) VALUES ('Annatha Anna Baduga song 👳☂️ Made for brothers ... - Ctn chandran songs', 'Baduga Artist', 'http://localhost/song/song4.mp3');INSERT INTO songs (title, artist_name, file_url) VALUES ('Baanuna Hunnave _ Baduga New Song _ Bugiri Studios _ Babu Kanna _ Thikisha Jivani _ Music BOJARAJ - BUGIRI STUDIOS', 'Baduga Artist', 'http://localhost/song/song5.mp3');INSERT INTO songs (title, artist_name, file_url) VALUES ('Badaga Song  Kanneruna Kadhaeya  Rare Sad Song - SathiyaKathi Hethae', 'Baduga Artist', 'http://localhost/song/song6.mp3');INSERT INTO songs (title, artist_name, file_url) VALUES ('Badaga song - Neeragi uttithaliyu -